// 1. Extraer el texto del Agente
const texto = $json.output || $json.text || "";

// 2. Buscar CUALQUIER URL de imagen en la respuesta (Drive, YCloud Dashboard, imgur, etc.)
// Primero intentamos extraer links en formato Markdown: [texto](URL)
const markdownLinks = [];
const mdRegex = /\[.*?\]\((https?:\/\/[^)]+)\)/g;
let mdMatch;
while ((mdMatch = mdRegex.exec(texto)) !== null) {
    markdownLinks.push(mdMatch[1]);
}

// Si no hay links Markdown, buscamos URLs directas
const directLinks = texto.match(/https?:\/\/[^\s)\]]+/g) || [];

// Unir ambas fuentes, priorizando los Markdown
const allUrls = markdownLinks.length > 0 ? markdownLinks : directLinks;

// Filtrar solo URLs que parezcan imágenes o vengan del dashboard
const imageExtensions = /\.(jpg|jpeg|png|gif|webp)(\?.*)?$/i;
const trustedDomains = /ycloud-dashboard|drive\.google\.com|uploads|imgur|cloudinary|storage/i;

const matches = allUrls.filter(url =>
    imageExtensions.test(url) || trustedDomains.test(url)
);

// Si no hay coincidencias filtradas, usar todas las URLs encontradas
const finalMatches = matches.length > 0 ? matches : allUrls;

// Helper: si es Google Drive, convertir a enlace de descarga directa
const extraerIdDrive = (url) => {
    const match = url.match(/(?:\/d\/|id=)([a-zA-Z0-9_-]{25,})/);
    return match ? match[1] : null;
};

const getImageUrl = (url) => {
    if (!url) return null;
    const driveId = extraerIdDrive(url);
    let finalUrl = driveId ? `https://drive.google.com/uc?export=view&id=${driveId}` : url;

    // Forzar HTTPS para el dashboard de ycloud y otras URLs de imágenes inseguras
    if (finalUrl.startsWith('http://')) {
        finalUrl = finalUrl.replace('http://', 'https://');
    }
    return finalUrl;
};

// 3. Obtener número del cliente
let remoteJid = null;
try {
    const datosWebhook = $('Webhook').item.json.body;
    remoteJid = datosWebhook.whatsappInboundMessage?.from || datosWebhook.from;
} catch (e) {
    remoteJid = null;
}

if (remoteJid) {
    remoteJid = remoteJid.replace(/\D/g, '');
    if (remoteJid.length === 8) remoteJid = '502' + remoteJid;
    if (!remoteJid.startsWith('+')) remoteJid = '+' + remoteJid;
}

return {
    tieneFotos: finalMatches.length > 0,
    foto1: finalMatches[0] ? getImageUrl(finalMatches[0]) : null,
    foto2: finalMatches[1] ? getImageUrl(finalMatches[1]) : null,
    remoteJid_fotos: remoteJid
};

const cache = $('Redis Cache').item.json.bot_status;
const webhookData = $('Webhook').item.json;

// Si Redis ya tiene flag, marcar como apagado
if (cache === 'manual') {
    return [{
        json: {
            ...webhookData,
            bot_apagado: true,
            origen: 'redis_cache'
        }
    }];
}

// Si no, revisar la respuesta de YCloud
const response = $input.item.json;
let contacts = [];

if (Array.isArray(response)) {
    contacts = response;
} else if (response.items) {
    contacts = response.items;
} else if (response.data) {
    contacts = response.data;
}

const contact = contacts[0] || {};
const tags = contact.tags || [];
const customAttrs = contact.customAttributes || {};

const tieneTag = tags.some(t => 
    String(t).toLowerCase() === 'bot_desactivado'
);
const tieneAttr = String(customAttrs.estado_bot || '').toLowerCase() === 'off';

const botApagado = tieneTag || tieneAttr;

return [{
    json: {
        ...webhookData,
        bot_apagado: botApagado,
        origen: botApagado ? 'ycloud' : 'activo',
        debug_tags: tags,
        debug_attrs: customAttrs,
        phoneNumber: webhookData.body.whatsappInboundMessage.from.replace(/\D/g, '')
    }
}];

options.systemMessage:
=={{ `Eres el agente de ventas de ${$json.agent_empresa || 'la empresa'}.

EMPRESA:
${$json.agent_descripcion || ''}

INSTRUCCIONES:
${$json.prompt_ventas || ''}

Sé conciso en WhatsApp (máximo 3-4 líneas). Responde siempre en Español. IMPORTANTE: Si la base de datos te proporciona un enlace de Imagen, DEBES enviarlo en tu respuesta obligatoriamente usando Markdown: [Ver Imagen](URL_DE_LA_IMAGEN).` }}

