// Parsear la respuesta del dashboard de forma segura
const raw = $input.item.json.data || $input.item.json.body || '{}';
let parsed = { botActive: false, priority: 'normal', handoff_reason: null, found: false };

try {
  const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  if (text.trim().startsWith('{')) {
    parsed = JSON.parse(text);
  }
} catch(e) {
  // Fallback: bot activo si hay error
}

return { json: parsed };

